export type ModifierKeyProps = {
  name: ModifierKeyName;
  os?: ModifierKeyOS;
  className?: string;
  "aria-label"?: string;
};

const KEY_LABELS: Record<ModifierKeyName, string> = {
  primary: "Command",
  secondary: "Option",
  shift: "Shift",
  control: "Control",
  enter: "Enter",
  tab: "Tab",
  backspace: "Backspace",
  delete: "Delete",
  space: "Space",
  "arrow-up": "Arrow up",
  "arrow-down": "Arrow down",
  "arrow-left": "Arrow left",
  "arrow-right": "Arrow right",
  home: "Home",
  end: "End",
  escape: "Escape",
};

export function ModifierKey(props: ModifierKeyProps) {
  const { name, os = "mac", className, "aria-label": ariaLabel } = props;
  const data = KEY_DATA[`${name}-${os}`];

  const classes = ["tt-modifier-key", className].filter(Boolean).join(" ");

  return (
    <span className={classes} role="img" aria-label={ariaLabel ?? KEY_LABELS[name]}>
      <svg
        viewBox={data.viewBox}
        fill="currentColor"
        xmlns="http://www.w3.org/2000/svg"
        aria-hidden="true"
      >
        {data.paths.map((d, i) => (
          <path key={i} d={d} />
        ))}
      </svg>
    </span>
  );
}

export type ShortcutProps = {
  keys: ModifierKeyName[];
  letter?: string;
  os?: ModifierKeyOS;
  className?: string;
  "aria-label"?: string;
  children?: ReactNode;
};

export function Shortcut(props: ShortcutProps) {
  const { keys, letter, os = "mac", className, "aria-label": ariaLabel, children } = props;

  const classes = ["tt-shortcut", className].filter(Boolean).join(" ");

  const defaultLabel = [
    ...keys.map((k) => KEY_LABELS[k]),
    letter ? letter.toUpperCase() : null,
  ]
    .filter(Boolean)
    .join(" + ");

  return (
    <span className={classes} role="img" aria-label={ariaLabel ?? defaultLabel}>
      {keys.map((k, i) => (
        <ModifierKey key={i} name={k} os={os} />
      ))}
      {letter && <span className="tt-shortcut__letter">{letter.toUpperCase()}</span>}
      {children}
    </span>
  );
}
